// get history — emits [{ wa_id, name, history:{ lastInbound, lastOutbound, last10Messages }, msgText, msgTextRaw, tsMs, mergeKey:1 }]

/* ---------- helpers ---------- */
const first = (...v) => v.find(x => x !== undefined && x !== null && x !== "");
const num = (v, d = null) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};
const toIso = (ms) => new Date(num(ms, Date.now())).toISOString();
const toMs = (iso, d = null) => {
  const t = Date.parse(iso || 0);
  return Number.isFinite(t) ? t : d;
};
const has = (o, k) => Object.prototype.hasOwnProperty.call(o || {}, k);
const normalizeText = (v) => String(v || "").replace(/\s+/g, " ").trim();

/* unwrap Firestore typed values (kept for any legacy rows) */
function unwrap(v) {
  if (v == null || typeof v !== "object") return v;
  if (has(v, "stringValue"))    return v.stringValue;
  if (has(v, "integerValue"))   return Number(v.integerValue);
  if (has(v, "doubleValue"))    return Number(v.doubleValue);
  if (has(v, "booleanValue"))   return !!v.booleanValue;
  if (has(v, "timestampValue")) return v.timestampValue;
  if (has(v, "mapValue"))       return v.mapValue?.fields || {};
  if (has(v, "arrayValue"))     return (v.arrayValue?.values || []).map(unwrap);
  return v;
}

/* Detect whether a row is Firestore-format (has typed field envelopes)
 * or flat API format (plain text/direction/ts_ms fields). */
function isFirestoreRow(row) {
  const f = row?.document?.fields || row?.fields;
  if (!f) return false;
  return Object.values(f).some(
    v =>
      v &&
      typeof v === "object" &&
      (has(v, "stringValue") || has(v, "integerValue") || has(v, "timestampValue"))
  );
}

/* Normalize a FLAT API message row → message object */
function normalizeFlatRow(row, fallbackWa, fallbackName) {
  const wa_id = String(first(row.wa_id, fallbackWa, "")).trim();
  const name = String(first(row.name, fallbackName, "")).trim();
  const text = String(first(row.text, "") || "").trim();
  if (!text) return null;

  let tsMs = num(row.ts_ms ?? row.tsMs, null);
  if (tsMs == null && row.ts_iso) tsMs = toMs(row.ts_iso, null);
  if (tsMs == null && row.tsIso) tsMs = toMs(row.tsIso, null);
  if (tsMs == null && row.created_at) tsMs = toMs(row.created_at, null);
  if (tsMs == null) tsMs = Date.now();

  const tsIso = first(row.ts_iso, row.tsIso, row.created_at) || toIso(tsMs);

  return {
    text,
    direction: row.direction || "inbound",
    tsIso,
    tsMs,
    wa_id,
    name,
    ...(row.ttlExpireAt ? { ttlExpireAt: row.ttlExpireAt } : {}),
  };
}

/* Normalize a FIRESTORE row → up to two message objects (inbound + optional outbound) */
function normalizeFirestoreRow(row, fallbackWa, fallbackName) {
  const doc = row?.document;
  const fieldsRaw = doc?.fields || row?.fields || {};
  const f = Object.fromEntries(
    Object.entries(fieldsRaw).map(([k, v]) => [k, unwrap(v)])
  );

  const wa_id = String(first(f.wa_id, fallbackWa, "")).trim();
  const name = String(first(f.name, fallbackName, "")).trim();

  const inboundTxt = first(f.text, f.inboundtext, "");
  const inboundIso = first(f.tsIso, null);
  let inboundTsMs = num(f.tsMs, null);
  if (inboundTsMs == null && inboundIso) inboundTsMs = toMs(inboundIso, null);
  if (inboundTsMs == null) inboundTsMs = Date.now();

  const inbound = inboundTxt
    ? {
        text: String(inboundTxt),
        direction: "inbound",
        tsIso: inboundIso || toIso(inboundTsMs),
        tsMs: inboundTsMs,
        wa_id,
        name,
        ...(f.ttlExpireAt ? { ttlExpireAt: f.ttlExpireAt } : {}),
      }
    : null;

  const outTxt = f.outbound_text;
  const outIso = f.outboundIso || null;
  let outTsMs = num(f.outboundTs, null);
  if (outTsMs == null && outIso) outTsMs = toMs(outIso, null);

  const outbound = outTxt
    ? {
        text: String(outTxt),
        direction: "outbound",
        tsIso: outIso || (outTsMs ? toIso(outTsMs) : null),
        tsMs: outTsMs || Date.now(),
        wa_id,
        name,
      }
    : null;

  const msgs = [];
  if (inbound) msgs.push(inbound);
  if (outbound) msgs.push(outbound);
  return msgs;
}

/* ---------- input ---------- */
const j = $json || {};

const wa_id = String(
  first(j.wa_id, j.fields?.wa_id?.stringValue, j.contacts?.[0]?.wa_id) || ""
).trim();

const name = String(
  first(j.name, j.fields?.name?.stringValue, j.contacts?.[0]?.profile?.name) || ""
).trim();

/* collect rows — messages array (flat API) takes priority */
let all = [];

if (Array.isArray(j.messages) && j.messages.length > 0) {
  for (const row of j.messages) {
    const msg = normalizeFlatRow(row, wa_id, name);
    if (msg) all.push(msg);
  }
} else {
  let rawRows = [];
  if (Array.isArray(j.results)) rawRows = rawRows.concat(j.results);
  if (j.document || j.fields) rawRows = rawRows.concat([j]);

  for (const row of rawRows) {
    if (isFirestoreRow(row)) {
      all.push(...normalizeFirestoreRow(row, wa_id, name));
    } else {
      const msg = normalizeFlatRow(row, wa_id, name);
      if (msg) all.push(msg);
    }
  }
}

/* current inbound payload from debounce-aware upstream */
const topText = String(first(j.msgText, j.text, j.fields?.text?.stringValue, "") || "").trim();
const topRawText = String(first(j.msgTextRaw, "") || "").trim();
const topIso = first(j.tsIso, j.fields?.tsIso?.stringValue, null);
let topTsMs = num(first(j.tsMs, j.fields?.tsMs?.integerValue), null);

if (topTsMs == null && topIso) topTsMs = toMs(topIso, null);

/* if ts is still missing, prefer latest stored inbound ts before falling back */
if (topTsMs == null) {
  const latestStoredInbound = [...all]
    .filter(m => m.direction === "inbound")
    .sort((a, b) => a.tsMs - b.tsMs)
    .pop();
  topTsMs = latestStoredInbound?.tsMs ?? (topText ? Date.now() : null);
}

const hasDebouncedBurst = !!topText && !!topRawText && normalizeText(topText) !== normalizeText(topRawText);

/* Only append the current top-level inbound when it is a real single message.
   For a debounced burst, do NOT append the synthetic combined text into history. */
if (topText && !hasDebouncedBurst) {
  const alreadyPresent = all.some(
    m => normalizeText(m.text) === normalizeText(topText) && num(m.tsMs, null) === topTsMs
  );

  if (!alreadyPresent) {
    all.push({
      text: topText,
      direction: "inbound",
      tsIso: topIso || toIso(topTsMs),
      tsMs: topTsMs,
      wa_id,
      name,
    });
  }
}

/* sort ascending by tsMs */
all = all
  .filter(m => !!m && m.tsMs != null)
  .sort((a, b) => (a.tsMs - b.tsMs) || String(a.tsIso || "").localeCompare(String(b.tsIso || "")));

/* window and picks */
const last10 = all.slice(-10);

const inboundAll = all.filter(m => m.direction === "inbound");
const outboundAll = all.filter(m => m.direction === "outbound");

const lastInboundBase = inboundAll.length ? inboundAll[inboundAll.length - 1] : {};
const lastOutbound = outboundAll.length ? outboundAll[outboundAll.length - 1] : {};

if (lastInboundBase.tsIso == null && lastInboundBase.tsMs) lastInboundBase.tsIso = toIso(lastInboundBase.tsMs);
if (lastOutbound.tsIso == null && lastOutbound.tsMs) lastOutbound.tsIso = toIso(lastOutbound.tsMs);

/* Debounce-aware logical latest inbound:
   keep stored history intact, but let downstream parsing see the burst as one turn. */
let lastInbound = { ...lastInboundBase };

if (topText) {
  if (hasDebouncedBurst) {
    const canOverlay =
      !lastInbound.text ||
      normalizeText(lastInbound.text) === normalizeText(topRawText) ||
      (topTsMs != null && num(lastInbound.tsMs, null) === topTsMs);

    if (canOverlay) {
      lastInbound = {
        ...lastInbound,
        text: topText,
        direction: "inbound",
        tsMs: topTsMs ?? lastInbound.tsMs ?? Date.now(),
        tsIso: topIso || lastInbound.tsIso || toIso(topTsMs ?? Date.now()),
        wa_id: lastInbound.wa_id || wa_id,
        name: lastInbound.name || name,
      };
    }
  } else if (!lastInbound.text) {
    lastInbound = {
      text: topText,
      direction: "inbound",
      tsMs: topTsMs ?? Date.now(),
      tsIso: topIso || toIso(topTsMs ?? Date.now()),
      wa_id,
      name,
    };
  }
}

/* LLM msgText = logical latest inbound */
const msgText = String(first(topText, lastInbound.text, ""));

/* stable top-level tsMs (logical latest inbound) */
const tsMs = num(lastInbound.tsMs, Date.now());

return [{
  json: {
    wa_id,
    name,
    history: {
      lastInbound,
      lastOutbound,
      last10Messages: last10,
    },
    msgText,
    msgTextRaw: topRawText,
    tsMs,
    tsIso: lastInbound.tsIso || toIso(tsMs),
    mergeKey: 1,
    debounceCount: Number(j.debounceCount ?? j.messageCount ?? 1),
    parts: Array.isArray(j.parts) ? j.parts : [],
    combinedTextFinal: String(first(j.combinedTextFinal, topText, "")),
  }
}];

// --- parse_analyse (v8 — smarter catalog matching, alias-aware cart enrichment, safe cart ops) ---
// Normalise parser output into a flat, stable object for downstream JS.
//
// Upgrades in v8:
//   - Keeps all v7 behaviour and references intact
//   - Enriches parser / history / context cart lines through catalog canonical names
//   - Uses safer alias-aware catalog scoring instead of exact alias-only lookup
//   - Adds product-family guardrails to reduce dirty alias mismatches
//   - Preserves richer mood + commercial fields when supplied by the parser
//   - Supports conservative local cart operations for explicit remove / reduce / replace turns
//   - Keeps the authoritative cart model: items_added = delta, cart_items = full cart

// ─────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────

const num = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};

const safeParse = (s) => {
  if (!s) return null;
  try { return JSON.parse(s); } catch { return null; }
};

const deriveTsMs = (iso) => {
  const n = iso ? Date.parse(iso) : NaN;
  return Number.isFinite(n) ? n : null;
};

const first = (...v) => v.find(x => x !== undefined && x !== null && x !== "");

const toLower = (s) => String(s || "").toLowerCase().trim();

const unwrapSingleObjectArray = (v) => {
  if (Array.isArray(v)) {
    if (v.length === 1 && v[0] && typeof v[0] === "object") return v[0];
    return {};
  }
  return (v && typeof v === "object") ? v : {};
};

const normaliseMsgText = (v) => {
  if (v === undefined || v === null) return "";
  const s = String(v).trim();
  if (!s || s.toLowerCase() === "undefined" || s.toLowerCase() === "null") return "";
  return s;
};

const normalizeTone = (tone) => {
  const t = String(tone || '').trim().toLowerCase();
  return ['concerned', 'cautious', 'neutral', 'warm', 'joyful', 'frustrated'].includes(t)
    ? t
    : 'neutral';
};

const normalizeEnergy = (energy) => {
  const e = String(energy || '').trim().toLowerCase();
  return ['low', 'steady', 'high'].includes(e) ? e : 'steady';
};

const normalizeCloseReadiness = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'low';
};

const normalizeResponseWeight = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['very_short', 'short', 'medium'].includes(s) ? s : 'short';
};

const normalizeNextMove = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['answer', 'clarify', 'reassure_then_ask', 'close', 'payment_followthrough', 'pause'].includes(s)
    ? s
    : 'answer';
};

const normalizeAfterPaymentMode = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['confirm_and_wait', 'confirm_and_reassure', 'confirm_and_logistics'].includes(s)
    ? s
    : 'confirm_and_wait';
};

const normalizeTimeBucket = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['morning', 'afternoon', 'evening', 'late'].includes(s) ? s : '';
};

const normalizeReceiptNameSource = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['profile', 'chat', 'unknown'].includes(s) ? s : 'unknown';
};

const normalizePatience = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'medium';
};

const normalizeConfidence = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'medium';
};

const normalizeUrgency = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'low';
};

const normalizeWarmth = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'medium';
};

const normalizeDirectness = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'medium';
};

const normalizeCustomerPriority = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return [
    'design_exactness',
    'price_total',
    'payment_progress',
    'production_status',
    'shipping_logistics',
    'delivery_risk',
    'package_completeness',
    ''
  ].includes(s) ? s : '';
};

const normalizeDesignStrictness = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'low';
};

const normalizeLogisticsSensitivity = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['low', 'medium', 'high'].includes(s) ? s : 'low';
};

const normalizeTrustTemperature = (v) => {
  const s = String(v || '').trim().toLowerCase();
  return ['stable', 'needs_reassurance', 'under_strain'].includes(s) ? s : 'stable';
};

// Preserve important flags while keeping a stable item shape.
const normaliseItem = (it) => ({
  name:           String(it?.name || "").trim(),
  qty:            num(it?.qty, 1),
  unit:           num(it?.unit, 0),
  total:          num(it?.total, 0),
  sku:            String(it?.sku || "").trim(),
  out_of_catalog: it?.out_of_catalog === true,
  pending_quote:  it?.pending_quote === true,
});

const itemIdentityKey = (it) => {
  const nameKey = toLower(it?.name).replace(/[^a-z0-9]/g, "");
  const skuKey  = toLower(it?.sku).replace(/[^a-z0-9]/g, "");
  return skuKey ? `${nameKey}|${skuKey}` : nameKey;
};

const dedupeItems = (items) => {
  const map = new Map();

  for (const raw of (Array.isArray(items) ? items : [])) {
    const it  = normaliseItem(raw);
    const key = itemIdentityKey(it);
    if (!key) continue;

    if (!map.has(key)) {
      map.set(key, { ...it });
      continue;
    }

    const prev  = map.get(key);
    const qty   = num(prev.qty, 0) + num(it.qty, 0);
    const unit  = num(prev.unit, 0) || num(it.unit, 0);
    const total = unit > 0
      ? qty * unit
      : num(prev.total, 0) + num(it.total, 0);

    map.set(key, {
      ...prev,
      qty,
      unit,
      total,
      out_of_catalog: prev.out_of_catalog || it.out_of_catalog,
      pending_quote:  prev.pending_quote  || it.pending_quote,
    });
  }

  return Array.from(map.values());
};

const stableSortItems = (items) =>
  (Array.isArray(items) ? items : [])
    .map(it => ({
      name:           String(it.name || ""),
      qty:            num(it.qty, 0),
      unit:           num(it.unit, 0),
      total:          num(it.total, 0),
      sku:            String(it.sku || ""),
      out_of_catalog: it.out_of_catalog === true,
      pending_quote:  it.pending_quote === true,
    }))
    .sort((a, b) =>
      `${a.name}|${a.sku}|${a.unit}|${a.qty}|${a.total}|${a.out_of_catalog}|${a.pending_quote}`
        .localeCompare(
          `${b.name}|${b.sku}|${b.unit}|${b.qty}|${b.total}|${b.out_of_catalog}|${b.pending_quote}`
        )
    );

const sameItems = (a, b) =>
  JSON.stringify(stableSortItems(a)) === JSON.stringify(stableSortItems(b));

const subtotalFromItems = (items) =>
  (Array.isArray(items) ? items : []).reduce((s, i) => {
    const it = normaliseItem(i);
    if (it.out_of_catalog || it.pending_quote) return s;
    return s + num(it.total, num(it.qty, 0) * num(it.unit, 0));
  }, 0);

const cloneItems = (items) => (Array.isArray(items) ? items.map(it => ({ ...normaliseItem(it) })) : []);

const uniqueStrings = (arr) => [...new Set((Array.isArray(arr) ? arr : []).map(v => String(v || "").trim()).filter(Boolean))];

function getCatalog() {
  let catalog = [];
  try { catalog = $('Set Catalog').first().json.catalog || []; } catch (_) {}
  if (!Array.isArray(catalog) || !catalog.length) {
    try { catalog = $json.catalog || []; } catch (_) {}
  }
  return Array.isArray(catalog) ? catalog : [];
}

const FAMILY_PATTERNS = [
  { family: 'cassock',   rx: /\bcassocks?\b/ },
  { family: 'alb',       rx: /\balbs?\b/ },
  { family: 'chasuble',  rx: /\bchasubles?\b/ },
  { family: 'stole',     rx: /\bstoles?\b/ },
  { family: 'cincture',  rx: /\bcinctures?\b|\bbelts?\b/ },
  { family: 'cope',      rx: /\bcopes?\b|\bmantles?\b/ },
  { family: 'mitre',     rx: /\bmitres?\b|\bmiters?\b/ },
  { family: 'shirt',     rx: /\bshirts?\b/ },
  { family: 'collar',    rx: /\bcollars?\b/ },
  { family: 'wine',      rx: /\bwines?\b|\bdevai\b|\befrat\b|\baltar\s+wine\b/ },
  { family: 'cup',       rx: /\bcups?\b/ },
  { family: 'tray',      rx: /\btrays?\b/ },
  { family: 'wafer',     rx: /\bwafers?\b|\bbread\b/ },
  { family: 'bible',     rx: /\bbibles?\b/ },
  { family: 'thurible',  rx: /\bthuribles?\b/ },
  { family: 'gown',      rx: /\bgowns?\b/ },
  { family: 'cope_set',  rx: /\bcope\s+set\b/ },
];

const normalizeCompare = (s) =>
  toLower(s)
    .replace(/[()]/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const compareTokens = (s) => normalizeCompare(s).split(' ').filter(Boolean);

const singulariseBasic = (s) => {
  const t = normalizeCompare(s);
  if (!t) return t;
  if (t.endsWith('ies') && t.length > 4) return t.slice(0, -3) + 'y';
  if (t.endsWith('ses') && t.length > 4) return t.slice(0, -2);
  if (t.endsWith('s') && !t.endsWith('ss') && t.length > 3) return t.slice(0, -1);
  return t;
};

const detectFamily = (s) => {
  const t = normalizeCompare(s);
  if (!t) return '';
  for (const { family, rx } of FAMILY_PATTERNS) {
    if (rx.test(t)) return family;
  }
  return '';
};

const scoreTokenOverlap = (wantedTokens, candidateTokens) => {
  if (!wantedTokens.length || !candidateTokens.length) return 0;
  const w = new Set(wantedTokens);
  const c = new Set(candidateTokens);
  let shared = 0;
  for (const token of w) if (c.has(token)) shared += 1;
  return shared;
};

function catalogMatchByName(name, catalog) {
  const wantedRaw = String(name || '').trim();
  if (!wantedRaw || !Array.isArray(catalog) || !catalog.length) return null;



  //PART 2 

    const wantedNorm = normalizeCompare(wantedRaw);
  const wantedSing = singulariseBasic(wantedRaw);
  const wantedTokens = compareTokens(wantedRaw);
  const wantedFamily = detectFamily(wantedRaw);

  let best = null;

  for (const item of catalog) {
    const itemName = String(item?.name || '').trim();
    const itemSku  = String(item?.sku || '').trim();
    const aliases  = Array.isArray(item?.aliases) ? item.aliases.map(a => String(a || '').trim()).filter(Boolean) : [];
    const candidates = [itemName, itemSku, ...aliases];
    const itemFamily = detectFamily([itemName, ...aliases].join(' '));

    let bestEntryScore = -Infinity;

    for (const candidate of candidates) {
      const candNorm = normalizeCompare(candidate);
      const candSing = singulariseBasic(candidate);
      const candTokens = compareTokens(candidate);
      if (!candNorm) continue;

      let score = 0;

      if (wantedRaw.toUpperCase() === itemSku.toUpperCase() && itemSku) score = 200;
      else if (wantedNorm === normalizeCompare(itemName)) score = 160;
      else if (wantedSing === singulariseBasic(itemName)) score = 150;
      else if (wantedNorm === candNorm) score = candidate === itemName ? 150 : 130;
      else if (wantedSing === candSing) score = candidate === itemName ? 145 : 120;
      else {
        const tokenOverlap = scoreTokenOverlap(wantedTokens, candTokens);
        const contains = candNorm.includes(wantedNorm) || wantedNorm.includes(candNorm);
        if (contains && Math.min(candNorm.length, wantedNorm.length) >= 4) {
          score = 90 + Math.min(candNorm.length, wantedNorm.length);
        } else if (tokenOverlap > 0) {
          score = 55 + (tokenOverlap * 10);
        }
      }

      if (score > 0 && wantedFamily && itemFamily && wantedFamily !== itemFamily) {
        score -= 80;
      }

      if (score > bestEntryScore) bestEntryScore = score;
    }

    if (bestEntryScore > 0 && (!best || bestEntryScore > best.score)) {
      best = { item, score: bestEntryScore };
    }
  }

  return best && best.score >= 60 ? best.item : null;
}

function applyCatalogToItem(rawItem, catalog) {
  const it = normaliseItem(rawItem);
  if (!it.name) return it;

  const match = catalogMatchByName(it.name, catalog);
  if (!match) {
    return {
      ...it,
      name: it.name,
      unit: it.unit || 0,
      total: it.total || 0,
      sku: it.sku || '',
      out_of_catalog: true,
    };
  }

  const unit = it.unit || num(match.price ?? match.unit, 0);
  const qty  = num(it.qty, 1);
  return {
    ...it,
    name: String(match.name || it.name).trim(),
    unit,
    total: unit > 0 ? qty * unit : num(it.total, 0),
    sku: it.sku || String(match.sku || '').trim(),
    out_of_catalog: false,
  };
}

function canonicalMatchInCart(refText, cartItems, catalog) {
  const ref = String(refText || '').trim();
  if (!ref) return null;

  const refCatalog = catalogMatchByName(ref, catalog);
  const refCanonical = refCatalog ? String(refCatalog.name || '').trim() : '';
  const refNorm = normalizeCompare(refCanonical || ref);
  const refFamily = detectFamily(refCanonical || ref);

  let best = null;
  for (const item of (Array.isArray(cartItems) ? cartItems : [])) {
    const itemCatalog = catalogMatchByName(item.name, catalog);
    const itemName = String(itemCatalog?.name || item.name || '').trim();
    const itemNorm = normalizeCompare(itemName);
    const itemFamily = detectFamily(itemName);
    let score = 0;

    if (refNorm && itemNorm && refNorm === itemNorm) score = 150;
    else if (refNorm && itemNorm && (itemNorm.includes(refNorm) || refNorm.includes(itemNorm)) && Math.min(refNorm.length, itemNorm.length) >= 4) score = 110;
    else {
      const overlap = scoreTokenOverlap(compareTokens(refNorm), compareTokens(itemNorm));
      if (overlap > 0) score = 60 + overlap * 10;
    }

    if (score > 0 && refFamily && itemFamily && refFamily !== itemFamily) score -= 70;

    if (score > 0 && (!best || score > best.score)) {
      best = { item, score };
    }
  }

  return best && best.score >= 60 ? best.item : null;
}

function parseQtyAndTarget(segment) {
  const s = normalizeCompare(segment);
  if (!s) return null;
  let qty = null;
  let target = s;

  const m1 = s.match(/^(\d+)\s+(.+)$/);
  if (m1) {
    qty = num(m1[1], 0);
    target = m1[2].trim();
  }

  target = target
    .replace(/^(the|my|this|that)\s+/i, '')
    .replace(/\s+(please|kindly)$/i, '')
    .trim();

  return target ? { qty, target } : null;
}

function detectLocalCartOperation(msgText, priorCart, catalog) {
  const text = String(msgText || '').trim();
  const lower = toLower(text);
  if (!lower) return null;

  const removeLead = lower.match(/^(?:remove|delete|cancel|leave out|dont include|don't include)\s+(.+)$/i);
  if (removeLead) {
    const parsed = parseQtyAndTarget(removeLead[1]);
    if (!parsed) return null;
    const match = canonicalMatchInCart(parsed.target, priorCart, catalog);
    if (!match) return null;
    return {
      type: parsed.qty && parsed.qty < num(match.qty, 0) ? 'decrease' : 'remove',
      target: match,
      qty: parsed.qty || num(match.qty, 0),
    };
  }

  const replaceLead = lower.match(/^(?:replace|change)\s+(.+?)\s+(?:with|to)\s+(.+)$/i) ||
                      lower.match(/^instead of\s+(.+?)\s+(?:use|add)\s+(.+)$/i);
  if (replaceLead) {
    const oldParsed = parseQtyAndTarget(replaceLead[1]);
    const newParsed = parseQtyAndTarget(replaceLead[2]);
    if (!oldParsed || !newParsed) return null;
    const oldMatch = canonicalMatchInCart(oldParsed.target, priorCart, catalog);
    if (!oldMatch) return null;
    const newItem = applyCatalogToItem({
      name: newParsed.target,
      qty: newParsed.qty || oldParsed.qty || num(oldMatch.qty, 1),
      unit: 0,
      total: 0,
      sku: '',
      out_of_catalog: false,
      pending_quote: false,
    }, catalog);
    return { type: 'replace', target: oldMatch, qty: num(oldMatch.qty, 0), replacement: newItem };
  }

  return null;
}

function mergeIncremental(baseCart, additions) {
  const map = new Map();

  for (const raw of (Array.isArray(baseCart) ? baseCart : [])) {
    const it = normaliseItem(raw);
    const key = itemIdentityKey(it);
    if (key) map.set(key, { ...it });
  }

  const incremental = [];

  for (const raw of (Array.isArray(additions) ? additions : [])) {
    const it  = normaliseItem(raw);
    const key = itemIdentityKey(it);
    if (!key) continue;

    if (map.has(key)) {
      const existing = map.get(key);
      const qty      = num(existing.qty, 0) + num(it.qty, 0);
      const unit     = num(existing.unit, 0) || num(it.unit, 0);
      const total    = unit > 0
        ? qty * unit
        : num(existing.total, 0) + num(it.total, 0);

      map.set(key, {
        ...existing,
        qty,
        unit,
        total,
        out_of_catalog: existing.out_of_catalog || it.out_of_catalog,
        pending_quote:  existing.pending_quote  || it.pending_quote,
      });

      incremental.push({
        ...it,
        qty: num(it.qty, 0),
      });
    } else {
      map.set(key, { ...it });
      incremental.push({ ...it });
    }
  }

  return {
    merged_cart: Array.from(map.values()),
    new_items: incremental,
  };
}

function subtractIncremental(baseCart, deltas) {
  const map = new Map();

  for (const raw of (Array.isArray(baseCart) ? baseCart : [])) {
    const it = normaliseItem(raw);
    const key = itemIdentityKey(it);
    if (key) map.set(key, { ...it });
  }

  for (const raw of (Array.isArray(deltas) ? deltas : [])) {
    const it  = normaliseItem(raw);
    const key = itemIdentityKey(it);
    if (!key || !map.has(key)) continue;

    const existing = map.get(key);
    const newQty   = num(existing.qty, 0) - num(it.qty, 0);

    if (newQty <= 0) {
      map.delete(key);
      continue;
    }

    const unit  = num(existing.unit, 0);
    const total = unit > 0
      ? newQty * unit
      : Math.max(0, num(existing.total, 0) - num(it.total, 0));

    map.set(key, {
      ...existing,
      qty: newQty,
      total,
    });
  }

  return Array.from(map.values());
}

// ─────────────────────────────────────────
// HISTORY CART — parse last10Messages
// Supports:
//   • KES full format:  • Name × qty — KES unit each = KES total
//   • KES short format: • Name × qty — KES total
//   • USD full format:  • Name × qty — $unit USD each = $total USD
//   • USD short format: • Name × qty — $total USD
//   • unavailable:      • Name × qty — not currently in stock
//   • pending quote:    • Name × qty — pending quote
// Deduplicates last10Messages by (tsMs + direction), preferring [Image] entries.
// ─────────────────────────────────────────

function deduplicateLast10(msgs) {
  const seen = new Map();

  for (const m of (Array.isArray(msgs) ? msgs : [])) {
    const key = `${m?.tsMs || ""}_${m?.direction || ""}`;
    const existing = seen.get(key);

    if (!existing) {
      seen.set(key, m);
      continue;
    }

    const existingText = String(existing?.text || "");
    const newText      = String(m?.text || "");

    if (!existingText.startsWith("[Image]") && newText.startsWith("[Image]")) {
      seen.set(key, m);
    }
  }

  return Array.from(seen.values()).sort((a, b) => num(a?.tsMs, 0) - num(b?.tsMs, 0));
}

function parseSummaryBullets(text) {  if (!text) return [];

  const items = [];
  const lines = String(text).split(/\r?\n/);

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!/^[•\-]/.test(line) || !/[×x]/.test(line)) continue;

    // Full KES
    let m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*KES\s*([\d,]+)\s*(?:each\s*)?=\s*KES\s*([\d,]+)/i);
    if (m) {
      const name  = m[1].trim();
      const qty   = num(m[2], 1);
      const unit  = num(m[3].replace(/,/g, ""), 0);
      const total = num(m[4].replace(/,/g, ""), qty * unit);
      items.push({ name, qty, unit, total, sku: "", out_of_catalog: false, pending_quote: false });
      continue;
    }

    // Short KES
    m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*KES\s*([\d,]+)\s*$/i);
    if (m) {
      const name  = m[1].trim();
      const qty   = num(m[2], 1);
      const total = num(m[3].replace(/,/g, ""), 0);
      const unit  = qty > 0 && total > 0 ? Math.round(total / qty) : 0;
      items.push({ name, qty, unit, total, sku: "", out_of_catalog: false, pending_quote: false });
      continue;
    }

    // Full USD
    m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*\$([\d,]+(?:\.\d+)?)\s*USD\s*(?:each\s*)?=\s*\$([\d,]+(?:\.\d+)?)\s*USD/i);
    if (m) {
      const name  = m[1].trim();
      const qty   = num(m[2], 1);
      const unit  = num(m[3].replace(/,/g, ""), 0);
      const total = num(m[4].replace(/,/g, ""), qty * unit);
      items.push({ name, qty, unit, total, sku: "", out_of_catalog: false, pending_quote: false });
      continue;
    }

    // Short USD
    m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*\$([\d,]+(?:\.\d+)?)\s*USD\s*$/i);
    if (m) {
      const name  = m[1].trim();
      const qty   = num(m[2], 1);
      const total = num(m[3].replace(/,/g, ""), 0);
      const unit  = qty > 0 && total > 0 ? +(total / qty).toFixed(2) : 0;
      items.push({ name, qty, unit, total, sku: "", out_of_catalog: false, pending_quote: false });
      continue;
    }

    // Unavailable / out of stock
    m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*(?:not currently in stock|unavailable)\s*$/i);
    if (m) {
      const name = m[1].trim();
      const qty  = num(m[2], 1);
      items.push({ name, qty, unit: 0, total: 0, sku: "", out_of_catalog: true, pending_quote: false });
      continue;
    }

    // Pending quote
    m = line.match(/^[•\-]\s*(.+?)\s*[×x]\s*(\d+)\s*[—–\-]+\s*pending quote\s*$/i);
    if (m) {
      const name = m[1].trim();
      const qty  = num(m[2], 1);
      items.push({ name, qty, unit: 0, total: 0, sku: "", out_of_catalog: false, pending_quote: true });
      continue;
    }
  }

  return dedupeItems(items);
}

function extractHistoryCart(history) {
  const raw = Array.isArray(history?.last10Messages) ? history.last10Messages : [];
  if (!raw.length) return [];

  const msgs = deduplicateLast10(raw);

  const outboundSummaries = msgs
    .filter(m =>
      String(m?.direction || "").toLowerCase() === "outbound" &&
      /[•\-].*[×x].*(KES|\$|not currently in stock|pending quote)/i.test(String(m?.text || ""))
    )
    .sort((a, b) => num(b?.tsMs, 0) - num(a?.tsMs, 0));

  if (!outboundSummaries.length) return [];

  return parseSummaryBullets(outboundSummaries[0].text);
}

// ─────────────────────────────────────────
// TEXT AMBIGUITY DETECTION
// ─────────────────────────────────────────

const ALWAYS_AMBIGUOUS = [
  { pattern: /\bcups?\b/,    root: "cup"    },
  { pattern: /\btrays?\b/,   root: "tray"   },
  { pattern: /\bwines?\b/,   root: "wine"   },
  { pattern: /\bcollars?\b/, root: "collar" },
  { pattern: /\bshirts?\b/,  root: "shirt"  },
];

const QUALIFIERS = {
  cup:    /\b(disposable|devai|prefilled|prefill|plastic|communion\s+cup)\b/,
  tray:   /\b(gold|silver|aluminium|aluminum|wooden|wood|with\s+lid|no\s+lid|without\s+lid)\b/,
  wine:   /\b(devai|efrat|altar|non.?alcoholic|alcoholic)\b/,
  collar: /\b(8|10|12|14|17|19|21)\s*(?:inch|in|"|'')?(?:\s|$)/,
  shirt:  /\b(bishop|normal|clerical)\b/,
};

function detectAmbiguity(msgText, catalog) {
  if (!msgText || !Array.isArray(catalog) || !catalog.length) return null;

  const lower = toLower(msgText);

  for (const { pattern, root } of ALWAYS_AMBIGUOUS) {
    if (!pattern.test(lower)) continue;

    const qualifierRx = QUALIFIERS[root];
    if (qualifierRx && qualifierRx.test(lower)) continue;

    const candidates = catalog
      .filter(item => {
        const name    = toLower(item?.name || "");
        const aliases = Array.isArray(item?.aliases) ? item.aliases.map(a => toLower(a)) : [];
        return name.includes(root) || aliases.some(a => a.includes(root));
      })
      .map(item => item?.name)
      .filter(Boolean);

    if (candidates.length >= 2) {
      return {
        ambiguousRoot: root,
        candidates,
        clarificationQuestion:
          `We have a few types of ${root} — which did you have in mind?\n` +
          candidates.map((n, i) => `${i + 1}. ${n}`).join("\n"),
      };
    }
  }

  return null;
}

// ─────────────────────────────────────────
// EXPLICIT CONFIRMATION DETECTION (narrowed)
// Plain "ok/okay/alright/noted/thanks" are NOT explicit order confirmation.
// ─────────────────────────────────────────

const CONFIRM_POSITIVE_PHRASES = /\b(yes|yeah|yep|sure|confirm(?:ed)?|proceed|go\s+ahead|place(?: the)? order|place it|send it|i(?:'m| am) ready|ndio|sawa|endelea)\b/i;
const ACK_ONLY_PHRASES         = /^(ok|okay|alright|noted|thanks|thank you|amen|👌|👍|🙏)$/i;

function customerHasConfirmed(text) {
  const t = normaliseMsgText(text);
  if (!t) return false;
  if (ACK_ONLY_PHRASES.test(t)) return false;
  return CONFIRM_POSITIVE_PHRASES.test(t);
}

// ─────────────────────────────────────────
// UNWRAP OpenAI / parser envelope
// ─────────────────────────────────────────

function parseAnalyseEnvelope(j) {
  if (!j) return {};

  if (j.lastInbound || j.cart || j.routingHint || j.image || j.commercial) {
    return unwrapSingleObjectArray(j);
  }

  try {
    const out        = Array.isArray(j.output) ? j.output[0] : j.output;
    const contentArr = out?.content || j.content || [];
    const textObj    = Array.isArray(contentArr)
      ? contentArr.find(c => c?.type === "output_text" || c?.type === "text")
      : null;
    const text   = textObj?.text || j.text;
    const parsed = safeParse(text);
    if (parsed) return unwrapSingleObjectArray(parsed);
  } catch (_) {}

  const direct = safeParse(typeof j?.text === "string" ? j.text : null);
  if (direct) return unwrapSingleObjectArray(direct);

  const all = safeParse(typeof j === "string" ? j : null);
  if (all) return unwrapSingleObjectArray(all);

  return {};
}

// ─────────────────────────────────────────
// NORMALISE PARSER-SUPPLIED IMAGE BLOCK
// ─────────────────────────────────────────

function normaliseImageState(image) {
  const img = image && typeof image === "object" ? image : {};
  return {
    isImage: !!img.isImage,
    customerIntent: [
      "inquiry_only",
      "soft_buy",
      "explicit_buy_with_qty",
      "buy_qty_missing",
      "compare_or_clarify",
      "unknown",
    ].includes(String(img.customerIntent || ""))
      ? String(img.customerIntent)
      : "unknown",
    bundleMatch: {
      matched: !!img.bundleMatch?.matched,
      catalog_name: String(img.bundleMatch?.catalog_name || "").trim(),
      confidence: ["high", "medium", "low"].includes(String(img.bundleMatch?.confidence || ""))
        ? String(img.bundleMatch.confidence)
        : "",
    },
    mainItem: {
      catalog_name: String(img.mainItem?.catalog_name || "").trim(),
      confidence: ["high", "medium", "low"].includes(String(img.mainItem?.confidence || ""))
        ? String(img.mainItem.confidence)
        : "",
    },
    autoAddCandidates: dedupeItems(img.autoAddCandidates),
    confirmCandidates: uniqueStrings(img.confirmCandidates),
    doNotAutoAdd: uniqueStrings(img.doNotAutoAdd),
  };
}

// ─────────────────────────────────────────
// MAIN
// ─────────────────────────────────────────

const a = parseAnalyseEnvelope($json);
const catalog = getCatalog();

// ── Last inbound / outbound ───────────────
const inboundTsIso = a.lastInbound?.tsIso || null;
const outboundTsIso = a.lastOutbound?.tsIso || null;

const fallbackMsgText = normaliseMsgText($json.msgText);

const normLastInbound = {
  wa_id: String(a.lastInbound?.wa_id || $json.wa_id || "").trim(),
  text: normaliseMsgText(first(a.lastInbound?.text, fallbackMsgText)),
  tsIso: inboundTsIso,
  tsMs: first(a.lastInbound?.tsMs, deriveTsMs(inboundTsIso)),
  direction: "inbound",
};

const normLastOutbound = {
  text: normaliseMsgText(a.lastOutbound?.text),
  tsIso: outboundTsIso,
  tsMs: first(a.lastOutbound?.tsMs, deriveTsMs(outboundTsIso)),
  direction: "outbound",
};

// ── Resolve msgText for checks ────────────
const msgTextForCheck = normaliseMsgText(
  first(
    normLastInbound.text,
    fallbackMsgText,
    a?.lastInbound?.text,
    $json.history?.lastInbound?.text
  )
);

const imageState = normaliseImageState(a.image);
const isImageMessage = imageState.isImage || msgTextForCheck.trimStart().startsWith("[Image]");

// ── Raw parser cart ───────────────────────
let ai_items_added = dedupeItems(
  (Array.isArray(a.cart?.items_added) ? a.cart.items_added : []).map(it => applyCatalogToItem(it, catalog))
);
const ai_cart_items = dedupeItems(
  (Array.isArray(a.cart?.cart_items) ? a.cart.cart_items : []).map(it => applyCatalogToItem(it, catalog))
);

// Rescue path for image soft-buy / explicit-buy if parser returned image candidates
// but failed to fill items_added.
if (
  isImageMessage &&
  ai_items_added.length === 0 &&
  ["soft_buy", "explicit_buy_with_qty"].includes(imageState.customerIntent) &&
  Array.isArray(imageState.autoAddCandidates) &&
  imageState.autoAddCandidates.length > 0
) {
  ai_items_added = dedupeItems(
    imageState.autoAddCandidates.map(it => applyCatalogToItem(it, catalog))
  );
}

// ── History / context carts ───────────────
const history_cart = dedupeItems(extractHistoryCart($json.history).map(it => applyCatalogToItem(it, catalog)));

const contextCartItemsRaw = Array.isArray($json.context?.state?.cart?.items)
  ? $json.context.state.cart.items
  : Array.isArray($json.context?.cart?.items)
    ? $json.context.cart.items
      : [];

const context_cart = dedupeItems(contextCartItemsRaw.map(it => applyCatalogToItem(it, catalog)));

// ─────────────────────────────────────────
// BUILD AUTHORITATIVE CART SNAPSHOT
// Priority:
//   1. Parser-supplied cart_items (full cart)
//   2. History rescue + merge parser items_added
//   3. Context cart rescue + merge parser items_added
//   4. Fresh order: cart_items = items_added
// Always return full authoritative cart_items.
// ─────────────────────────────────────────

let items_added = cloneItems(ai_items_added);
let cart_items = [];

if (ai_cart_items.length > 0) {
  cart_items = cloneItems(ai_cart_items);
} else if (history_cart.length > 0) {
  const merged = mergeIncremental(history_cart, items_added);
  cart_items = merged.merged_cart;
  items_added = merged.new_items;
} else if (context_cart.length > 0) {
  const merged = mergeIncremental(context_cart, items_added);
  cart_items = merged.merged_cart;
  items_added = merged.new_items;
} else {
  cart_items = cloneItems(items_added);
}


// Conservative local cart-op rescue.
// Only runs when parser did not emit a new delta and the latest inbound clearly expresses remove / reduce / replace.
const localCartOp = (!isImageMessage && ai_items_added.length === 0)
  ? detectLocalCartOperation(msgTextForCheck, cart_items, catalog)
  : null;

if (localCartOp?.type === 'remove' && localCartOp.target) {
  cart_items = subtractIncremental(cart_items, [{ ...localCartOp.target, qty: localCartOp.qty }]);
  items_added = [];
} else if (localCartOp?.type === 'decrease' && localCartOp.target) {
  cart_items = subtractIncremental(cart_items, [{ ...localCartOp.target, qty: localCartOp.qty }]);
  items_added = [];
} else if (localCartOp?.type === 'replace' && localCartOp.target && localCartOp.replacement) {
  cart_items = subtractIncremental(cart_items, [{ ...localCartOp.target, qty: localCartOp.qty }]);
  const merged = mergeIncremental(cart_items, [localCartOp.replacement]);
  cart_items = dedupeItems(merged.merged_cart.map(it => applyCatalogToItem(it, catalog)));
  items_added = dedupeItems(merged.new_items.map(it => applyCatalogToItem(it, catalog)));
}

// ─────────────────────────────────────────
// CONTEXT CART GUARD
// If current cart still looks incomplete and context cart exists,
// merge context cart + current delta carefully (increment, don't overwrite).
// Skip if history rescue already supplied the prior cart.
// ─────────────────────────────────────────

const contextSubtotal = num(
  $json.context?.state?.cart?.subtotal ??
  $json.context?.cart?.subtotal,
  0
);

const analyseSubtotal = subtotalFromItems(cart_items);
const cartLooksIncomplete =
  (cart_items.length === 0 && context_cart.length > 0) ||
  (cart_items.length > 0 && contextSubtotal > 0 && analyseSubtotal < contextSubtotal * 0.5);

const historyRescueRan = ai_cart_items.length === 0 && history_cart.length > 0;

if (cartLooksIncomplete && context_cart.length > 0 && !historyRescueRan) {
  const merged = mergeIncremental(context_cart, items_added);
  cart_items = merged.merged_cart;
  items_added = merged.new_items.length ? merged.new_items : items_added;
}

// ─────────────────────────────────────────
// OTHER SECTIONS
// ─────────────────────────────────────────

const known = {
  item:           String(a.known?.item || "").trim(),
  qty:            a.known?.qty ?? "",
  method:         String(a.known?.method || "").trim(),
  location:       String(a.known?.location || "").trim(),
  payment:        String(a.known?.payment || "").trim(),
  oneQuestionKey: String(a.known?.oneQuestionKey || "").trim(),
};

if (a.known?.itemCandidates)        known.itemCandidates        = Array.isArray(a.known.itemCandidates) ? a.known.itemCandidates : [];
if (a.known?.ambiguousRoot)         known.ambiguousRoot         = String(a.known.ambiguousRoot || "");
if (a.known?.clarificationQuestion) known.clarificationQuestion = String(a.known.clarificationQuestion || "");

const mood = {
  tone:             normalizeTone(a.mood?.tone),
  score:            num(a.mood?.score, 0),
  energy:           normalizeEnergy(a.mood?.energy),
  patience:         normalizePatience(a.mood?.patience),
  confidence:       normalizeConfidence(a.mood?.confidence),
  urgency:          normalizeUrgency(a.mood?.urgency),
  warmth:           normalizeWarmth(a.mood?.warmth),
  directness:       normalizeDirectness(a.mood?.directness),
  emojiCount:       num(a.mood?.emojiCount, 0),
  exclamationCount: num(a.mood?.exclamationCount, 0),
  questionCount:    num(a.mood?.questionCount, 0),
  mentions:         Array.isArray(a.mood?.mentions) ? a.mood.mentions : [],
  wantsPOD:         !!a.mood?.wantsPOD,
};

const commercial = {
  closeReadiness:       normalizeCloseReadiness(a.commercial?.closeReadiness),
  responseWeight:       normalizeResponseWeight(a.commercial?.responseWeight),
  nextMove:             normalizeNextMove(a.commercial?.nextMove),
  afterPaymentMode:     normalizeAfterPaymentMode(a.commercial?.afterPaymentMode),
  customerPriority:     normalizeCustomerPriority(a.commercial?.customerPriority),
  answerDebt: {
    exists: !!a.commercial?.answerDebt?.exists,
    topic:  String(a.commercial?.answerDebt?.topic || '').trim(),
  },
  designStrictness:     normalizeDesignStrictness(a.commercial?.designStrictness),
  logisticsSensitivity: normalizeLogisticsSensitivity(a.commercial?.logisticsSensitivity),
  trustTemperature:     normalizeTrustTemperature(a.commercial?.trustTemperature),
};

const fallbackWaId = String(
  first(
    normLastInbound.wa_id,
    $json.wa_id,
    $json.history?.lastInbound?.wa_id,
    $json.history?.lastOutbound?.wa_id,
    ""
  )
).trim();

const confirm = {
  phoneCandidate:    String(a.confirm?.phoneCandidate || fallbackWaId || "").trim(),
  nameCandidate:     String(a.confirm?.nameCandidate || "").trim(),
  needsNameConfirm:  !!a.confirm?.needsNameConfirm,
  shouldAskOnce:     !!a.confirm?.shouldAskOnce,
  receiptNameSource: normalizeReceiptNameSource(a.confirm?.receiptNameSource),
};

const flags = {
  offeredAddOnOnce: !!a.flags?.offeredAddOnOnce,
  askedNameOnce:    !!a.flags?.askedNameOnce,
  askedConfirmOnce: !!a.flags?.askedConfirmOnce,
};

const greeting = {
  bucket:                  String(a.greeting?.bucket || "").trim(),
  localHourEAT:            a.greeting?.localHourEAT ?? "",
  localTimeBucket:         normalizeTimeBucket(a.greeting?.localTimeBucket),
  wasGreetingOnly:         !!a.greeting?.wasGreetingOnly,
  greetMismatch:           !!a.greeting?.greetMismatch,
  countryAware:            !!a.greeting?.countryAware,
  countryName:             a.greeting?.countryName || "",
  shouldUseCountryMention: !!a.greeting?.shouldUseCountryMention,

  lastGreetingAt:          String(a.greeting?.lastGreetingAt || "").trim(),
  hasGreetedIn12hWindow:   !!a.greeting?.hasGreetedIn12hWindow,
  hoursSinceGreeting:      a.greeting?.hoursSinceGreeting ?? "",
  isFreshThread:           !!a.greeting?.isFreshThread,
  shouldWelcomeBack:       !!a.greeting?.shouldWelcomeBack,
  elapsedFriendly:         String(a.greeting?.elapsedFriendly || "").trim(),
};

const timing = {
  seenGapMinutes: num(a.timing?.seenGapMinutes, 0),
  isReturning:    !!a.timing?.isReturning,
};

const routingHint = {
  suggestedNextAction: ["reply", "await", "orderCheck"].includes(String(a.routingHint?.suggestedNextAction || ""))
    ? String(a.routingHint.suggestedNextAction)
    : (isImageMessage ? "reply" : "reply"),
};

// ─────────────────────────────────────────
// AMBIGUITY CHECK (text only; image uses parser image block)
// Preserve prior cart instead of wiping everything.
// ─────────────────────────────────────────

let ambiguity = a.ambiguity || null;

if (!ambiguity && !isImageMessage) {
  const localAmbiguity = detectAmbiguity(msgTextForCheck, catalog);
  if (localAmbiguity) ambiguity = localAmbiguity;
}

if (ambiguity) {
  known.oneQuestionKey = "item_clarification";
  known.item = String(ambiguity.ambiguousRoot || known.item || "").trim();
  known.itemCandidates = Array.isArray(ambiguity.candidates) ? ambiguity.candidates : (known.itemCandidates || []);
  known.ambiguousRoot = String(ambiguity.ambiguousRoot || "").trim();
  known.clarificationQuestion = String(ambiguity.clarificationQuestion || "").trim();

  // Block only the new ambiguous addition.
  // Preserve prior cart from history/context/full cart where possible.
  items_added = [];

  if (history_cart.length > 0) {
    cart_items = cloneItems(history_cart);
  } else if (context_cart.length > 0) {
    cart_items = cloneItems(context_cart);
  } else if (ai_cart_items.length > 0 && ai_items_added.length > 0) {
    cart_items = subtractIncremental(ai_cart_items, ai_items_added);
