}

// ─────────────────────────────────────────
// EXPLICIT CONFIRMATION
// Use parser value if it explicitly provided true/false, then OR with local narrowed detection.
// ─────────────────────────────────────────

const parserExplicitConfirm =
  typeof a.customerExplicitlyConfirmed === "boolean"
    ? a.customerExplicitlyConfirmed
    : false;

const customerExplicitlyConfirmed = parserExplicitConfirm || customerHasConfirmed(msgTextForCheck);

// ─────────────────────────────────────────
// FINAL CART DERIVATION
// ─────────────────────────────────────────

cart_items = dedupeItems(cart_items.map(it => applyCatalogToItem(it, catalog)));
items_added = dedupeItems(items_added.map(it => applyCatalogToItem(it, catalog)));

const out_of_catalog_items = uniqueStrings([
  ...(Array.isArray(a.cart?.out_of_catalog_items) ? a.cart.out_of_catalog_items : []),
  ...cart_items.filter(i => i.out_of_catalog).map(i => i.name),
  ...items_added.filter(i => i.out_of_catalog).map(i => i.name),
]);

const finalSubtotal = subtotalFromItems(cart_items);

// Ensure inquiry-only image messages do not silently carry image auto-adds forward.
if (
  isImageMessage &&
  ["inquiry_only", "compare_or_clarify", "buy_qty_missing", "unknown"].includes(imageState.customerIntent) &&
  ai_items_added.length === 0 &&
  !parserExplicitConfirm
) {
  items_added = [];
}

// ─────────────────────────────────────────
// COMPOSE FINAL OUTPUT
// ─────────────────────────────────────────

const parsed = {
  wa_id: fallbackWaId,

  lastInbound:  normLastInbound,
  lastOutbound: normLastOutbound,

  cart: {
    items_added,
    cart_items,
    cart_subtotal: finalSubtotal,
    out_of_catalog_items,
  },

  known,
  image: imageState,
  mood,
  commercial,
  confirm,
  flags,
  greeting,
  timing,
  routingHint,

  requiresClarification: !!ambiguity,
  ambiguity: ambiguity || null,
  customerExplicitlyConfirmed,

  isImageMessage,
  msgText: msgTextForCheck,
  mergeKey: 1,
};

return [parsed];

// === Compose Context (v10.1 — session-state forwarding + isDuplicateOrder) ===
// [FIX-10] Forward 15 session-state fields from rawApiCtx into context
// [FIX-11] isDuplicateOrder forwarded from rawApiCtx to context and top-level

const num = (v, d = 0) => { const n = Number(v); return Number.isFinite(n) ? n : d; };
const toLower = (s) => String(s || '').toLowerCase().trim();
const nowIso = () => new Date().toISOString();
const deriveTsMsSafe = (iso) => { const t = iso ? Date.parse(iso) : NaN; return Number.isFinite(t) && t > 0 ? t : Date.now(); };
const toFirstName = (name) => String(name || '').trim().split(/\s+/).filter(Boolean)[0] || '';
const first = (...v) => v.find(x => x !== undefined && x !== null && x !== '');
const normalizeMsgText = (v) => { if (v === undefined || v === null) return ''; const s = String(v).trim(); if (!s || s.toLowerCase() === 'undefined' || s.toLowerCase() === 'null') return ''; return s; };
const normalizeTone = (v) => { const t = String(v||'').trim().toLowerCase(); return ['concerned','cautious','neutral','warm','joyful','frustrated'].includes(t)?t:'neutral'; };
const normalizeEnergy = (v) => { const e = String(v||'').trim().toLowerCase(); return ['low','steady','high'].includes(e)?e:'steady'; };
const normalizeCloseReadiness = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'low'; };
const normalizeResponseWeight = (v) => { const s = String(v||'').trim().toLowerCase(); return ['very_short','short','medium'].includes(s)?s:'short'; };
const normalizeNextMove = (v) => { const s = String(v||'').trim().toLowerCase(); return ['answer','clarify','reassure_then_ask','close','payment_followthrough','pause'].includes(s)?s:'answer'; };
const normalizeAfterPaymentMode = (v) => { const s = String(v||'').trim().toLowerCase(); return ['confirm_and_wait','confirm_and_reassure','confirm_and_logistics'].includes(s)?s:'confirm_and_wait'; };
const normalizeTimeBucket = (v) => { const s = String(v||'').trim().toLowerCase(); return ['morning','afternoon','evening','late'].includes(s)?s:''; };
const normalizeReceiptNameSource = (v) => { const s = String(v||'').trim().toLowerCase(); return ['profile','chat','unknown'].includes(s)?s:'unknown'; };
const normalizePatience = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'medium'; };
const normalizeConfidence = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'medium'; };
const normalizeUrgency = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'low'; };
const normalizeWarmth = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'medium'; };
const normalizeDirectness = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'medium'; };
const normalizeCustomerPriority = (v) => { const s = String(v||'').trim().toLowerCase(); return ['design_exactness','price_total','payment_progress','production_status','shipping_logistics','delivery_risk','package_completeness',''].includes(s)?s:''; };
const normalizeDesignStrictness = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'low'; };
const normalizeLogisticsSensitivity = (v) => { const s = String(v||'').trim().toLowerCase(); return ['low','medium','high'].includes(s)?s:'low'; };
const normalizeTrustTemperature = (v) => { const s = String(v||'').trim().toLowerCase(); return ['stable','needs_reassurance','under_strain'].includes(s)?s:'stable'; };
const uniqueStrings = (arr) => [...new Set((Array.isArray(arr)?arr:[]).map(v=>String(v||'').trim()).filter(Boolean))];
const extractCountryCodeFallback = (wa) => { const d = String(wa||'').replace(/\D/g,''); if(!d) return ''; const k=['254','255','256','257','250','251','252','253','211','27','20','234','233','44','1']; return k.find(c=>d.startsWith(c))||d.slice(0,3); };
const getNodeJson = (name) => { try { return $(name)?.item?.json||null; } catch { return null; } };
const getNodeItems = (name) => { try { const r=$(name).all(); if(Array.isArray(r)) return r.map(x=>x.json??x); } catch{} try { const o=$(name)?.item?.json; if(o) return [o]; } catch{} return []; };
const normalizeDialCodeList = (v) => String(v||'').split(',').map(p=>String(p||'').replace(/\D/g,'').trim()).filter(Boolean);
const getCountryRows = () => { const r=[...getNodeItems('countrycodes'),...getNodeItems('Countrycodes')]; if(r.length&&r.every(x=>x&&(x.country||x.code||x.iso))) return r; if(Array.isArray($json?.countries)) return $json.countries; return []; };
const getDialCodeVariants = (rows) => { const s=new Set(); for(const r of rows||[]) for(const c of normalizeDialCodeList(r?.code)) s.add(c); return [...s].sort((a,b)=>b.length-a.length); };
const extractCountryCodeFromRows = (wa,rows) => { const d=String(wa||'').replace(/\D/g,''); if(!d) return ''; return getDialCodeVariants(rows).find(c=>d.startsWith(c))||''; };
const findCountryByDialCode = (dialCode,rows) => { const c=String(dialCode||'').replace(/\D/g,''); if(!c) return null; for(const r of rows||[]) if(normalizeDialCodeList(r?.code).includes(c)) return r; return null; };

// ── Catalog ───────────────────────────────────────────────────────────────────
let catalogItems = [];
try { const raw=$('When Called by Main Workflow').first().json.catalog; catalogItems=Array.isArray(raw)?raw:[]; } catch(e){}
if(!catalogItems.length) { try { catalogItems=$('Set Catalog').first().json.catalog||[]; } catch(e){} }
if(!catalogItems.length) { try { catalogItems=Array.isArray($json.catalog)?$json.catalog:[]; } catch(e){} }

function matchCatalogItems(text) {
  if(!text||!catalogItems.length) return [];
  const lower=toLower(text);
  return catalogItems.filter(item=>{
    const name=toLower(item.name||''); const sku=toLower(item.sku||'');
    const aliases=Array.isArray(item.aliases)?item.aliases.map(a=>toLower(a)):[];
    return lower.includes(name)||lower.includes(sku)||aliases.some(a=>a&&lower.includes(a));
  }).map(item=>({name:item.name,sku:item.sku,price:item.price??item.unit??0,currency:'KES',in_stock:item.in_stock??true,category:item.category??''}));
}

const userFacts = $json.user||{};

// ── Country ───────────────────────────────────────────────────────────────────
const countryRows=getCountryRows();
let countryCode=String($json.phone_country_code||'').replace(/\D/g,'');
let countryName=$json.phone_country_name||'';
