}
const isKenyaNumber=countryCode==='254'||countryIso==='KE'||toLower(countryName)==='kenya';

const fromHistory=getNodeJson('get history')||getNodeJson('Get History')||null;
const fromParseAnalyse=getNodeJson('parse_analyse')||null;

