const interceptMode=rawApiCtx?.intercept_mode||rawApiCtx?.interceptMode||'ai';
const recentIntercept=rawApiCtx?.recent_intercept||rawApiCtx?.recentIntercept||null;
const handoverHint=(()=>{
  if(!recentIntercept) return '';
