  'bishop shirt (black)':            { name:'Bishop Shirt (Black)',          unit:4500, sku:'BISHOP-BLK' },
  'clerical shirt':                  { name:'Clerical Shirt (Normal)',       unit:2200, sku:'SHIRT-NORM' },
  'collar':                          { name:'Clerical Collar (standard)',    unit:350,  sku:'COLLAR-STD' },
  'clerical collar 21 inch':         { name:'Clerical Collar 21"',           unit:1500, sku:'COLLAR-21'  },
};

// ── Item helpers ──────────────────────────────────────────────────────────────
const normaliseItem = (it) => ({name:String(it?.name||'').trim(),qty:num(it?.qty,1),unit:num(it?.unit,0),total:num(it?.total,0),sku:String(it?.sku||'').trim(),out_of_catalog:it?.out_of_catalog===true,pending_quote:it?.pending_quote===true});
const itemIdentityKey = (it) => { const nk=toLower(it?.name).replace(/[^a-z0-9]/g,''); const sk=toLower(it?.sku).replace(/[^a-z0-9]/g,''); return sk?`${nk}|${sk}`:nk; };
const dedupeItems = (items) => { const map=new Map(); for(const raw of (Array.isArray(items)?items:[])){const it=normaliseItem(raw);const key=itemIdentityKey(it);if(!key) continue;if(!map.has(key)){map.set(key,{...it});continue;}const prev=map.get(key);const qty=num(prev.qty,0)+num(it.qty,0);const unit=num(prev.unit,0)||num(it.unit,0);const total=unit>0?qty*unit:num(prev.total,0)+num(it.total,0);map.set(key,{...prev,qty,unit,total,out_of_catalog:prev.out_of_catalog||it.out_of_catalog,pending_quote:prev.pending_quote||it.pending_quote});}return Array.from(map.values()); };
const subtotalFromItems = (items) => (Array.isArray(items)?items:[]).reduce((s,raw)=>{const it=normaliseItem(raw);if(it.out_of_catalog||it.pending_quote) return s;return s+num(it.total,num(it.qty,0)*num(it.unit,0));},0);
const mergeIncremental = (baseCart,additions) => { const map=new Map(); for(const raw of (Array.isArray(baseCart)?baseCart:[])){const it=normaliseItem(raw);const key=itemIdentityKey(it);if(key) map.set(key,{...it});} const incremental=[]; for(const raw of (Array.isArray(additions)?additions:[])){const it=normaliseItem(raw);const key=itemIdentityKey(it);if(!key) continue;if(map.has(key)){const ex=map.get(key);const qty=num(ex.qty,0)+num(it.qty,0);const unit=num(ex.unit,0)||num(it.unit,0);const total=unit>0?qty*unit:num(ex.total,0)+num(it.total,0);map.set(key,{...ex,qty,unit,total,out_of_catalog:ex.out_of_catalog||it.out_of_catalog,pending_quote:ex.pending_quote||it.pending_quote});incremental.push({...it});}else{map.set(key,{...it});incremental.push({...it});}} return{merged_cart:Array.from(map.values()),new_items:incremental}; };

// ── Family patterns (FIX-9) ───────────────────────────────────────────────────
const FAMILY_PATTERNS_CC=[
  {family:'cassock',rx:/\bcassocks?\b/},{family:'alb',rx:/\balbs?\b/},{family:'chasuble',rx:/\bchasubles?\b/},
  {family:'stole',rx:/\bstoles?\b/},{family:'cincture',rx:/\bcinctures?\b|\bbelts?\b/},{family:'cope',rx:/\bcopes?\b|\bmantles?\b/},
  {family:'mitre',rx:/\bmitres?\b|\bmiters?\b/},{family:'shirt',rx:/\bshirts?\b/},{family:'collar',rx:/\bcollars?\b/},
  {family:'wine',rx:/\bwines?\b|\bdevai\b|\befrat\b|\baltar\s+wine\b/},{family:'cup',rx:/\bcups?\b/},{family:'tray',rx:/\btrays?\b/},
  {family:'wafer',rx:/\bwafers?\b|\bbread\b/},{family:'bible',rx:/\bbibles?\b/},{family:'thurible',rx:/\bthuribles?\b/},{family:'gown',rx:/\bgowns?\b/},
];
const detectFamilyCC=(s)=>{const t=toLower(s);for(const{family,rx}of FAMILY_PATTERNS_CC){if(rx.test(t))return family;}return '';};
const enrichSKU=(item)=>{
  const iName=toLower(item.name||''); const iFamily=detectFamilyCC(item.name||'');
  const scored=catalogItems.map(c=>{const cName=toLower(c.name||'');const aliases=Array.isArray(c.aliases)?c.aliases.map(a=>toLower(a)):[];const cFamily=detectFamilyCC([c.name,...aliases].join(' '));let score=0;if(cName===iName)score=100;else if(aliases.includes(iName))score=90;else if(cName.includes(iName)&&iName.length>4)score=50+iName.length;else if(iName.includes(cName)&&cName.length>4)score=40+cName.length;else{const b=aliases.filter(a=>Math.min(a.length,iName.length)>4&&(a.includes(iName)||iName.includes(a))).sort((a,b)=>b.length-a.length)[0];if(b)score=30+b.length;}if(score>0&&iFamily&&cFamily&&iFamily!==cFamily)score-=80;return{entry:c,score};}).filter(m=>m.score>0).sort((a,b)=>b.score-a.score);
  const cm=scored.length?scored[0].entry:null;
  if(cm){const unit=num(cm.price??cm.unit??item.unit,0);const qty=num(item.qty,1);return{...item,name:cm.name,qty,unit,total:unit>0?qty*unit:num(item.total,0),sku:item.sku||cm.sku||'',out_of_catalog:false};}
  const ref=fallbackMap[iName]||{};
  if(ref.unit){const unit=num(ref.unit,0);const qty=num(item.qty,1);return{...item,name:ref.name||item.name,qty,unit,total:unit>0?qty*unit:num(item.total,0),sku:item.sku||ref.sku||'',out_of_catalog:false};}
  return{...item,qty:num(item.qty,1),unit:0,total:0,sku:'',out_of_catalog:true};
};

// ── Image detection ───────────────────────────────────────────────────────────
const isImageMessage=(()=>{if(typeof $json.isImageMessage==='boolean')return $json.isImageMessage;if(typeof fromParseAnalyse?.isImageMessage==='boolean')return fromParseAnalyse.isImageMessage;return String($json.msgText||($json.imageAnalysis?'[Image]':'')||'').trimStart().startsWith('[Image]');})();

function deduplicateLast10(msgs){const s=new Map();for(const m of (Array.isArray(msgs)?msgs:[])){const key=`${m.tsMs||''}_${m.direction||''}`;const ex=s.get(key);if(!ex)s.set(key,m);else if(!String(ex.text||'').startsWith('[Image]')&&String(m.text||'').startsWith('[Image]'))s.set(key,m);}return Array.from(s.values()).sort((a,b)=>num(a.tsMs,0)-num(b.tsMs,0));}

// ── History + parser ─────────────────────────────────────────────────────────
const j=$json||{};
const currentHistory=j.history||fromHistory?.history||{};
const currentAi=(j.lastInbound||j.cart||j.known||j.mood||j.image||j.commercial)?j:(fromParseAnalyse||{});
const lastInbound=currentAi.lastInbound||currentHistory.lastInbound||{};
const lastOutbound=currentAi.lastOutbound||currentHistory.lastOutbound||{};
const raw10=Array.isArray(currentHistory.last10Messages)?currentHistory.last10Messages:[];
const last10=deduplicateLast10(raw10);
const wa_id=String(j.wa_id||lastInbound.wa_id||lastOutbound.wa_id||fromHistory?.wa_id||currentHistory.wa_id||'').trim();
if(!wa_id) throw new Error('ComposeContext Guard: wa_id missing.');

const liText=normalizeMsgText(lastInbound.text);
const loText=normalizeMsgText(lastOutbound.text);
const liIso=lastInbound.tsIso||null;
const loIso=lastOutbound.tsIso||null;
const liTsMs=lastInbound.tsMs||deriveTsMsSafe(liIso);
const loTsMs=lastOutbound.tsMs||deriveTsMsSafe(loIso);

const imageAnalysis=(()=>{if(!isImageMessage)return '';if($json.imageAnalysis)return String($json.imageAnalysis).trim();const body=liText.replace(/^\[Image\]\s*/i,'');const ni=body.indexOf('\n\nCustomer note:');return(ni>=0?body.slice(0,ni):body).trim();})();
const imageCaption=(()=>{if(!isImageMessage)return '';if($json.userCaption)return String($json.userCaption).trim();const ni=liText.indexOf('\n\nCustomer note:');if(ni<0)return '';return liText.slice(ni+'\n\nCustomer note:'.length).trim();})();

const rawImage=currentAi.image&&typeof currentAi.image==='object'?currentAi.image:{};
const imageState={
  isImage:!!rawImage.isImage||isImageMessage,
  customerIntent:String(rawImage.customerIntent||''),
  bundleMatch:{matched:!!rawImage.bundleMatch?.matched,catalog_name:String(rawImage.bundleMatch?.catalog_name||'').trim(),confidence:String(rawImage.bundleMatch?.confidence||'').trim()},
  mainItem:{catalog_name:String(rawImage.mainItem?.catalog_name||'').trim(),confidence:String(rawImage.mainItem?.confidence||'').trim()},
  autoAddCandidates:dedupeItems((Array.isArray(rawImage.autoAddCandidates)?rawImage.autoAddCandidates:[]).map(normaliseItem).map(enrichSKU)),
  confirmCandidates:uniqueStrings(rawImage.confirmCandidates),
  doNotAutoAdd:uniqueStrings(rawImage.doNotAutoAdd),
