VESTMENT ITEM HINT
={{ (() => {
const vestmentFamily = ["cassock","alb","chasuble","cope","gown","stole","mitre","cincture","robe","vestment"];
const latestIn  = String($json.context?.lastText_inbound  || "").toLowerCase();
const latestOut = String($json.context?.lastText_outbound || "").toLowerCase();
const knownItem = String($json.context?.known?.item       || "").toLowerCase();
const cartNames = ($json.context?.cart?.cart_items || $json.context?.cart?.full_cart || [])
  .map(i => String(i?.name || "").toLowerCase());
const allText = [latestIn, latestOut, knownItem, ...cartNames].join(" ");
const isVestment = vestmentFamily.some(v => allText.includes(v));
if (!isVestment) return JSON.stringify({
  isVestment: false, isOverlayItem: false, baseGarmentKnown: true,
  colourKnown: false, genderKnown: false, accessoriesKnown: false,
  needsBaseGarment: false, needsColour: false, needsGender: false, needsAccessories: false
});
// Overlay items (chasuble, cope) need base garment clarification FIRST
const overlayItems = ["chasuble","cope"];
const focusItem = overlayItems.find(v => (latestIn.includes(v) || knownItem.includes(v)));
const isOverlayItem = !!focusItem;
const baseGarmentClues = ["over a cassock","over the cassock","over an alb","over the alb","with cassock","with alb","over cassock","over alb","cassock set","alb set"];
const baseGarmentKnown = !isOverlayItem || baseGarmentClues.some(c => allText.includes(c));
// Colour detection
const colourWords = ["black","white","red","blue","green","purple","maroon","gold","silver","grey","gray","brown","cream","ivory","navy","scarlet","crimson","royal","violet"];
const colourKnown = colourWords.some(c => allText.includes(c));
// Gender detection — role words imply gender
const genderWords = ["gentleman","lady","ladies","man","woman","male","female","men","women","his","her","pastor","bishop","apostle","prophet","reverend","elder","priest","father","sister","deacon"];
const genderKnown = genderWords.some(g => allText.includes(g));
// For stole/cincture/mitre, gender is not required
const genderExemptItems = ["stole","cincture","mitre"];
const focusItemType = vestmentFamily.find(v => allText.includes(v)) || "";
const genderExempt = genderExemptItems.includes(focusItemType);
// Accessory detection — check if accessory discussion has happened
const accessoryAskedInLastOut = latestOut.includes("full set") || latestOut.includes("single piece") || latestOut.includes("which accessories") || latestOut.includes("accessories would you") || latestOut.includes("on its own") || latestOut.includes("add a stole") || latestOut.includes("add a cope") || latestOut.includes("add a chasuble") || latestOut.includes("which would you like to include") || latestOut.includes("on top");
const customerAnsweredAcc = latestIn.includes("full set") || latestIn.includes("single piece") || latestIn.includes("just the") || latestIn.includes("on its own") || latestIn.includes("standalone") || latestIn.includes("no accessories") || latestIn.includes("stole") || latestIn.includes("cincture") || latestIn.includes("shirt") || latestIn.includes("collar") || latestIn.includes("cope") || latestIn.includes("chasuble") || /^(yes|no|sure|ok|okay|none|just)\b/i.test(latestIn.trim());
const accessoriesKnown = accessoryAskedInLastOut && customerAnsweredAcc;
// For items that have no accessories (stole, cincture, mitre alone), mark accessories as not-needed
const noAccessoryItems = ["stole","cincture","mitre"];
const accessoriesNotApplicable = noAccessoryItems.includes(focusItemType);
return JSON.stringify({
  isVestment: true,
  isOverlayItem,
  baseGarmentKnown,
  colourKnown: !!colourKnown,
  genderKnown: genderExempt || !!genderKnown,
  accessoriesKnown: accessoriesNotApplicable || !!accessoriesKnown,
  needsBaseGarment: isOverlayItem && !baseGarmentKnown,
  needsColour: !colourKnown,
  needsGender: !genderExempt && !genderKnown,
  needsAccessories: !accessoriesNotApplicable && colourKnown && (genderExempt || genderKnown) && !accessoriesKnown && (!isOverlayItem || baseGarmentKnown)
});
})() }}

