={{ (() => {
const t = String($json.context?.lastText_inbound || "").toLowerCase().trim();
if (!t) return "business_question";
const hasEmail = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i.test(t);
const greetingOnly = ["hi","hello","hey","shalom","warm greetings","praise jesus","good morning","good afternoon","good evening"].includes(t);
const ackOnly = ["ok","okay","alright","noted","thanks","thank you","amen","👍","🙏","✅"].includes(t);
const deferPhrases = ["not now","later","tomorrow","next week","when i am ready","when i'm ready","when i get back","when i'm back","i will send later","after weekend","after the weekend"];
const objectionPhrases = ["too much","too expensive","your price is high","your price is too high","cost is high","expensive","can you reduce","last price","best price"];
const complaintPhrases = ["damaged","wrong item","spoilt","spoiled","delay","late","refund","complaint","problem"];
const decisionPhrases = ["yes","confirm","proceed","go ahead","place the order","sawa","ndio","endelea"];
const orderingSignals = ["order","cart","checkout","delivery","pickup","ship","shipping","invoice","receipt","pay","payment"];
const productSignals = ["price","how much","quote","size","colour","color","add","remove","change","cassock","alb","wine","wafer","collar","bible","tray","cup","stole","mitre","thurible"];
const nonBuyingSignals = ["registration","legal requirements","business setup","dealership","wholesale advice","certificate","document","presbytery","alliance","moderator"];
// Cart complete detection — must run before ackOnly check
const lastOut = String($json.context?.lastText_outbound || "").toLowerCase();
const prevWasCartBuilding = lastOut.includes("anything else") || lastOut.includes("add anything") || lastOut.includes("new subtotal");
const cartCompletePhrases = ["that is all","that's all","that'll be all","no","nope","no more","nothing else","nothing more","those are the items","those are all","that is everything","that's everything","done","that's it","i'm done","we're done","that's enough","no other","no additional","just those","just that"];
const cartHasItems = ($json.context?.cart?.cart_items || $json.context?.cart?.full_cart || []).length > 0;
const isCartComplete = prevWasCartBuilding && cartHasItems && cartCompletePhrases.some(p => t === p || t.startsWith(p) || t.endsWith(p));
if (isCartComplete) return "cart_complete";
if (complaintPhrases.some(p => t.includes(p))) return "issue_or_complaint";
if (objectionPhrases.some(p => t.includes(p))) return "objection_or_value_resistance";
if (decisionPhrases.some(p => t === p || t.includes(p))) return "decision_ready";
if (hasEmail && !orderingSignals.some(p => t.includes(p))) return "email_only";
if (greetingOnly) return "greeting_only";
if (ackOnly) return "acknowledgement_only";
if (deferPhrases.some(p => t.includes(p))) return "defer_or_later";
if (nonBuyingSignals.some(p => t.includes(p)) && !productSignals.some(p => t.includes(p))) return "non_buying_out_of_scope";
if (orderingSignals.some(p => t.includes(p))) return "order_progress";
if (productSignals.some(p => t.includes(p))) return "product_discovery";
return "business_question";
})() }}

