parameters.jsCode:
/**
 * Node: Extract User Facts (v2)
 *
 * NAME:     Never from chat. Source = WhatsApp profile name only.
 *           - New customer  → set from WhatsApp name (handled at Create User API).
 *           - Existing customer, name missing → patch from WhatsApp name now.
 *           - Existing customer, name present → never touch.
 *
 * PHONE:    Always locked to wa_id from WhatsApp. Never changed.
 *
 * EMAIL:    Extracted from chat text if not already set on the user record.
 *           Once set, only a human agent can change it via the web UI.
 *
 * LOCATION: Extracted from chat text if not already set on the user record.
 *           Once set, only a human agent can change it via the web UI.
 *
 * AGE:      Extracted from chat text if not already set on the user record.
 *           Once set, only a human agent can change it via the web UI.
 */

// ── Identity ─────────────────────────────────────────────────
const wa_id = String($json?.wa_id || $json?.context?.wa_id || "").trim();
if (!wa_id) throw new Error("Extract User Facts: wa_id missing");

// ── Existing user record ──────────────────────────────────────
// Read DIRECTLY from Get User API — this is the authoritative
// database record, unaffected by any downstream merging.
// Never trust $json.name or $json.user.name — those may be
// contaminated by Wrap → user flattening the record into $json.
let _getUserRecord = {};
try { _getUserRecord = $('Get User API').item.json || {}; } catch(e) {}

const existingName     = String(_getUserRecord.name     || "").trim();
const existingEmail    = String(_getUserRecord.email    || "").trim();
const existingLocation = String(_getUserRecord.location || "").trim();
const existingAge      = (_getUserRecord.age != null && _getUserRecord.age !== "")
                           ? _getUserRecord.age
                           : null;

// ── WhatsApp profile name ─────────────────────────────────────
// Read ONLY from Extract Sender ID — the raw WhatsApp contacts payload.
// Never read from $json.name, which may already contain the existing
// user's database name (merged in by Wrap → user).
let _whatsappRaw = "";
try { _whatsappRaw = $('Extract Sender ID').item.json.whatsappName || ""; } catch(e) {}
const whatsappName = String(_whatsappRaw).trim();

// ── Chat text (for email / location / age only) ──────────────
const textRaw = $json?.context?.lastText_inbound ?? $json?.msgText ?? "";
const text = String(textRaw).trim();

// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

const trimOnce = (s) => String(s || "").replace(/\s+/g, " ").trim();

function titleCase(s) {
  return trimOnce(s)
    .toLowerCase()
    .replace(/\b([a-z][a-z']*)\b/g, (m) => m[0].toUpperCase() + m.slice(1));
}

function normPhone(x) {
  if (!x) return null;
  const s = String(x).trim();
  const hasPlus = s.startsWith("+");
  const digits = s.replace(/[^\d]/g, "");
  if (!hasPlus && /^254\d{9}$/.test(digits)) return "+" + digits;
  return (hasPlus ? "+" : "") + digits || null;
}

function pickEmail(t) {
  const m = t.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return m ? m[0].toLowerCase() : null;
}

function pickAge(t) {
  const TICK = "[''`]";
  const m =
    t.match(new RegExp(`\\b(?:age\\s*(?:is)?|i${TICK}?m|i\\s+am|am)\\s*(\\d{1,3})(?:\\s*(?:years?|yrs?\\.))?\\b`, "i")) ||
    t.match(/\b(\d{1,3})\s*(?:years?|yrs?\.?)\b/i);
  const n = m ? Number(m[1]) : NaN;
  return Number.isFinite(n) && n >= 12 && n <= 110 ? n : null;
}

function pickLocation(t) {
  const m = t.match(/\b(?:in|at|uko|katika|from)\s+([A-Za-z][A-Za-z\s,'-]{2,60})/i);
  if (!m) return null;
  let loc = m[1];
  const STOP = /\b(?:and|but|then|i|i'm|i am|am|want|would|to|for|buy|purchase|need|order|please)\b/i;
  const stopIdx = loc.search(STOP);
  if (stopIdx > 0) loc = loc.slice(0, stopIdx);
  loc = loc.split(/[.!?]/)[0];
  loc = loc.replace(/\s{2,}/g, " ").trim();
  if (loc.length < 3) return null;
  return loc.split(/\s+/)
    .map((w) => (w.match(/^[a-z]/) ? w[0].toUpperCase() + w.slice(1).toLowerCase() : w))
    .join(" ");
}

// ─────────────────────────────────────────────────────────────
// BUILD PATCH — field-by-field rules
// ─────────────────────────────────────────────────────────────

const fields = {};

// ── NAME ─────────────────────────────────────────────────────
// Only write when the database record has no name at all.
// Source is WhatsApp profile name exclusively — never chat text.
// existingName comes directly from Get User API, so it is always
// the true database value regardless of any downstream merging.
if (!existingName && whatsappName) {
  fields.name       = { stringValue: titleCase(whatsappName) };
  fields.nameSource = { stringValue: "whatsapp_profile" };
}

// ── PHONE ────────────────────────────────────────────────────
// Always normalised from wa_id. Backend treats this as insert-only.
const normalisedPhone = normPhone(wa_id);
if (normalisedPhone) {
  fields.phone = { stringValue: normalisedPhone };
}

// ── EMAIL ────────────────────────────────────────────────────
// Extract from chat, but only write if not already in the database.
if (!existingEmail) {
  const email = pickEmail(text);
  if (email) fields.email = { stringValue: email };
}

// ── LOCATION ─────────────────────────────────────────────────
// Extract from chat, but only write if not already in the database.
if (!existingLocation) {
  const location = pickLocation(text);
  if (location) fields.location = { stringValue: location };
}

// ── AGE ──────────────────────────────────────────────────────
// Extract from chat, but only write if not already in the database.
if (existingAge == null) {
  const age = pickAge(text);
  if (age != null) fields.age = { integerValue: String(age) };
}

// ── TIMESTAMP ────────────────────────────────────────────────
fields.updatedAt = { timestampValue: new Date().toISOString() };

// ─────────────────────────────────────────────────────────────
// Only emit a patch when there is at least one meaningful field
// beyond updatedAt — avoids no-op writes on every message.
// ─────────────────────────────────────────────────────────────
const substantiveKeys = Object.keys(fields).filter(k => k !== "updatedAt");

const factsUpdateMask = Object.keys(fields)
  .map((k) => `updateMask.fieldPaths=${encodeURIComponent(k)}`)
  .join("&");

return [{
  wa_id,
  factsPatch:      substantiveKeys.length > 0 ? fields : {},
  factsUpdateMask: substantiveKeys.length > 0 ? factsUpdateMask : "",
  hasUpdate:       substantiveKeys.length > 0,
  mergeKey: 1,
}];

const input = $input.first().json;

return [{
  json: {
    wa_id:    input.wa_id,
    phone:    input.factsPatch?.phone?.stringValue ?? null,
    name:     input.factsPatch?.name?.stringValue ?? null,
    email:    input.factsPatch?.email?.stringValue ?? null,
    location: input.factsPatch?.location?.stringValue ?? null,
    age:      input.factsPatch?.age?.integerValue 
              ? parseInt(input.factsPatch.age.integerValue) 
              : null,
  }
}];
